// Message processor
async function processMessage(message) {
  const startTime = Date.now();
  const correlationId = message.properties.correlationId || uuidv4();

  let parsedContent;
  try {
    const content = message.content.toString('utf-8');

    // Limit message size (1MB)
    if (content.length > 1024 * 1024) {
      throw new Error('Message exceeds maximum size of 1MB');
    }

    parsedContent = JSON.parse(content);
  } catch (err) {
    logger.error('Failed to parse message', { error: err.message, correlationId });
    throw new Error(`Invalid JSON message: ${err.message}`);
  }

  const { type, payload, metadata } = parsedContent;

  if (!type) {
    throw new Error('Message type is required');
  }

  if (!payload || typeof payload !== 'object') {
    throw new Error('Message payload is required and must be an object');
  }

  validateMessageType(type);

  const handler = messageHandlers[type];
  if (!handler) {
    throw new Error(`No handler registered for message type: ${type}`);
  }

  logger.info('Processing message', { type, correlationId, metadata });

  const result = await handler(payload);

  const duration = Date.now() - startTime;
  logger.info('Message processed successfully', { type, correlationId, duration: `${duration}ms` });

  return result;
}

// RabbitMQ connection and consumer
class MessageConsumer {
  constructor() {
    this.connection = null;
    this.channel = null;
    this.isShuttingDown = false;
    this.retryCount = 0;
    this.maxRetries = 10;
  }

  async connect() {
    try {
      logger.info('Connecting to RabbitMQ', { url: config.rabbitmq.url.replace(/\/\/.*@/, '//***@') });

      this.connection = await amqp.connect(config.rabbitmq.url);

      this.connection.on('error', (err) => {
        logger.error('RabbitMQ connection error', { error: err.message });
      });

      this.connection.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ connection closed, attempting reconnect');
          this.reconnect();
        }
      });

      this.channel = await this.connection.createChannel();

      this.channel.on('error', (err) => {
        logger.error('RabbitMQ channel error', { error: err.message });
      });

      this.channel.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ channel closed');
        }
      });

      // Set prefetch
      await this.channel.prefetch(config.rabbitmq.prefetch);

      // Assert dead letter exchange and queue
      await this.channel.assertExchange('dlx_exchange', 'direct', { durable: true });
      await this.channel.assertQueue(config.rabbitmq.deadLetterQueue, {
        durable: true,
        arguments: {
          'x-message-ttl': 86400000, // 24 hours
        },
      });
      await this.channel.bindQueue(config.rabbitmq.deadLetterQueue, 'dlx_exchange', 'dead_letter');

      // Assert main queue with dead letter configuration
      await this.channel.assertQueue(config.rabbitmq.queue, {
        durable: true,
        arguments: {
          'x-dead-letter-exchange': 'dlx_exchange',
          'x-dead-letter-routing-key': 'dead_letter',
        },
      });

      this.retryCount = 0;
      logger.info('Connected to RabbitMQ successfully');
    } catch (err) {
      logger.error('Failed to connect to RabbitMQ', { error: err.message });
      throw err;
    }
  }

  async reconnect() {
    if (this.isShuttingDown) return;

    this.retryCount++;
    if (this.retryCount > this.maxRetries) {
      logger.error('Max reconnection attempts reached, exiting');
      process.exit(1);
    }

    const delay = Math.min(config.rabbitmq.reconnectDelay * Math.pow(2, this.retryCount - 1), 60000);
    logger.info(`Reconnecting in ${delay}ms (attempt ${this.retryCount}/${this.maxRetries})`);

    setTimeout(async () => {
      try {
        await this.connect();
        await this.startConsuming();
      } catch (err) {
        logger.error('Reconnection failed', { error: err.message });
        this.reconnect();
      }
    }, delay);
  }

  async startConsuming() {
    logger.info('Starting to consume messages', { queue: config.rabbitmq.queue });

    await this.channel.consume(config.rabbitmq.queue, async (message) => {
      if (!message) return;

      const messageId = message.properties.messageId || 'unknown';
      const retryCount = (message.properties.headers && message.properties.headers['x-retry-count']) || 0;
      const maxMessageRetries = 3;

      try {
        await processMessage(message);
        this.channel.ack(message);
      } catch (err) {
        logger.error('Failed to process message', {
          messageId,
          error: err.message,
          retryCount,
        });

        if (retryCount < maxMessageRetries) {
          // Requeue with incremented retry count
          const headers = { ...message.properties.headers, 'x-retry-count': retryCount + 1 };
          this.channel.nack(message, false, false);

          // Re-publish with delay via headers
          try {
            this.channel.publish('', config.rabbitmq.queue, message.content, {
              ...message.properties,
              headers,
            });
          } catch (publishErr) {
            logger.error('Failed to republish message for retry', { messageId, error: publishErr.message });
          }
        } else {
          // Send to dead letter queue
          logger.warn('Message exceeded max retries, sending to DLQ', { messageId, retryCount });
          this.channel.nack(message, false, false);
        }
      }
    }, {
      noAck: false,
    });

    logger.info('Consumer started successfully');
  }

  async shutdown() {
    this.isShuttingDown = true;
    logger.info('Shutting down gracefully');

    try {
      if (this.channel) {
        await this.channel.close();
        logger.info('Channel closed');
      }
      if (this.connection) {
        await this.connection.close();
        logger.info('Connection closed');
      }
      await pool.end();
      logger.info('Database pool closed');
    } catch (err) {
      logger.error('Error during shutdown', { error: err.message });
    }

    process.exit(0);
  }
}

